from __future__ import annotations
from dataclasses import dataclass, field
from decimal import Decimal
from datetime import date
from enum import Enum
from typing import Dict, Optional


class GuardrailTier(str, Enum):
    CLEAR    = "clear"       # < 80%
    ALERT    = "alert"       # 80% <= x < 95%
    THROTTLE = "throttle"    # 95% <= x < 100%
    BLOCKED  = "blocked"     # >= 100%


@dataclass
class BudgetEntry:
    cost_centre: str
    period: date                # first day of billing month
    budget_usd: Decimal
    accumulated_usd: Decimal = Decimal("0")

    def add_cost(self, cost: Decimal) -> GuardrailTier:
        """Update accumulated cost and return the resulting guardrail tier."""
        self.accumulated_usd += cost
        return self.current_tier()

    def utilisation(self) -> float:
        if self.budget_usd == 0:
            return 1.0
        return float(self.accumulated_usd / self.budget_usd)

    def current_tier(self) -> GuardrailTier:
        u = self.utilisation()
        if u >= 1.0:
            return GuardrailTier.BLOCKED
        elif u >= 0.95:
            return GuardrailTier.THROTTLE
        elif u >= 0.80:
            return GuardrailTier.ALERT
        return GuardrailTier.CLEAR


@dataclass
class BudgetGuardrailSystem:
    entries: Dict[str, BudgetEntry] = field(default_factory=dict)
    # priority_tags: calls with these tags bypass block (tier 3)
    priority_features: frozenset = frozenset({"incident-response", "fraud-critical"})

    def register(self, cost_centre: str, period: date, budget_usd: Decimal) -> None:
        key = f"{cost_centre}:{period}"
        self.entries[key] = BudgetEntry(cost_centre, period, budget_usd)

    def record_and_check(
        self,
        cost_centre: str,
        period: date,
        cost: Decimal,
        feature: str = "",
    ) -> tuple[GuardrailTier, bool]:
        """
        Record the cost and return (tier, allowed).
        Returns (BLOCKED, False) when budget exhausted, unless feature is priority.
        """
        key = f"{cost_centre}:{period}"
        entry = self.entries.get(key)
        if not entry:
            return GuardrailTier.CLEAR, True  # no budget configured = no restriction
        tier = entry.add_cost(cost)
        if tier == GuardrailTier.BLOCKED and feature not in self.priority_features:
            return tier, False
        return tier, True

import time
from collections import deque
from dataclasses import dataclass, field

@dataclass
class TokenRateLimiter:
    """Sliding-window TPM limiter applied when tier-2 kicks in."""
    max_tokens_per_minute: int = 50_000          # reduced cap at tier-2
    _window: deque = field(default_factory=deque)  # (timestamp, token_count) tuples

    def _purge_old(self) -> None:
        cutoff = time.monotonic() - 60.0
        while self._window and self._window[0][0] < cutoff:
            self._window.popleft()

    def tokens_used_last_minute(self) -> int:
        self._purge_old()
        return sum(t for _, t in self._window)

    def allow(self, requested_tokens: int) -> bool:
        self._purge_old()
        if self.tokens_used_last_minute() + requested_tokens <= self.max_tokens_per_minute:
            self._window.append((time.monotonic(), requested_tokens))
            return True
        return False   # caller must back-off or escalate
